def fix_spaces(text):
    result = []
    i = 0
    n = len(text)
    while i < n:
        if text[i] == ' ':
            j = i
            while j < n and text[j] == ' ':
                j += 1
            count = j - i
            result.append('-' if count > 2 else '_' * count)
            i = j
        else:
            result.append(text[i])
            i += 1
    return ''.join(result)

